mapper.select:
SELECT CAND_ID, STFF_TYPE_CD, STFF_NM, STFF_EXP_YR, OVRL_RTG, SIGN_BONUS, ANSL_SAL FROM STFF_CAND
WHERE STFF_TYPE_CD = #{stffTypeCd}
ORDER BY OVRL_RTG DESC

SELECT CAND_ID, STFF_TYPE_CD, STFF_NM, STFF_EXP_YR, OVRL_RTG, SIGN_BONUS, ANSL_SAL
FROM STFF_CAND
WHERE CAND_ID = #{candId}

SELECT S.STFF_ID, S.STFF_NM, S.STFF_TYPE_CD, S.STFF_EXP_YR, S.STFF_ANSL_SAL, S.STFF_STTS_CD
FROM STFF S
WHERE S.TM_ID = #{tmId}
  AND S.STFF_TYPE_CD = #{stffTypeCd}
  AND S.STFF_STTS_CD = 'AT'

mapper.insert:
INSERT INTO GAME_CFG (CFG_KEY, CFG_VAL)
VALUES (#{cfgKey}, #{cfgVal})
ON DUPLICATE KEY UPDATE CFG_VAL = #{cfgVal}
